import { computed, Injectable, signal } from '@angular/core';

import { BaseEntity } from '../../../shared/models';

@Injectable({ providedIn: 'root' })
export class BulkSelectionService {
  private readonly _checkedItems = signal<BaseEntity[]>([]);
  readonly checkedItems = this._checkedItems.asReadonly();
  readonly isBulkMode = computed(() => this._checkedItems().length > 1);

  setAll(items: BaseEntity[]): void {
    this._checkedItems.set(items);
  }

  toggle(item: BaseEntity): void {
    const current = this._checkedItems();
    const existingIndex = current.findIndex((i) => i.id === item.id);
    this._checkedItems.set(
      existingIndex === -1 ? [...current, item] : current.filter((_, itemIndex) => itemIndex !== existingIndex),
    );
  }

  isChecked(item: BaseEntity): boolean {
    return this._checkedItems().some((checkedItem) => checkedItem.id === item.id);
  }

  clear(): void {
    this._checkedItems.set([]);
  }
}
