/* eslint-disable @angular-eslint/prefer-inject */
import { Inject, Injectable, Injector, Optional, Type } from '@angular/core';
import { GridConfiguration, GridConfigurationEntry } from '../../models';
import { GRID_CONFIGS } from '../../../core/models';
import { GridConfigRegistryService } from '../../services/grid-config-registry.service';

/**
 * Factory for creating grid configurations
 * @class GridConfigurationFactory
 */
@Injectable()
export class GridConfigurationFactory {
  private readonly configs = new Map<
    string,
    Type<GridConfiguration<unknown>>
  >();
  private readonly instanceCache = new Map<
    string,
    GridConfiguration<unknown>
  >();

  /**
   * Creates an instance of GridConfigurationFactory
   * @param {Injector} injector - Angular injector for dependency injection
   * @param {GridConfigurationEntry[][]} configurations - Array of grid configuration entries
   */
  constructor(
    private readonly injector: Injector,
    @Optional() private readonly registry: GridConfigRegistryService | null,
    @Optional()
    @Inject(GRID_CONFIGS)
    configurations: GridConfigurationEntry[][] = [],
  ) {
    const flatConfigs = configurations.flat();
    for (const { entityType, config } of flatConfigs) {
      this.configs.set(entityType, config);
    }
  }

  /**
   * Creates a grid configuration instance.
   * Uses singleton pattern - returns cached instance if available, re-initializing with new params.
   * @template T Type of data managed by the grid
   * @param {ValidGridTypes} entityType - Type of grid configuration to create
   * @param {Record<string, string | number>} params - Configuration parameters
   * @returns {GridConfiguration<T>} The created grid configuration
   * @throws {InvalidGridTypeError} If the grid type is not valid
   * @throws {GridConfigurationError} If configuration creation fails
   */
  create<T>(
    entityType: string,
    params: Record<string, string | number>,
  ): GridConfiguration<T> {
    // Check cache first for singleton behavior
    const cached = this.instanceCache.get(entityType);
    if (cached !== undefined) {
      cached.initialize(params); // Re-initialize with new params
      return cached as GridConfiguration<T>;
    }

    const ConfigClass = this.configs.get(entityType);
    if (!ConfigClass) {
      throw new Error(`No grid configuration found for type: ${entityType}`);
    }
    const config = this.injector.get(ConfigClass) as GridConfiguration<T>;
    // Initialize BEFORE registering to ensure config is fully initialized
    config.initialize(params);
    // Register with the registry if available (optional for better testability)
    this.registry?.register(config);
    // Cache the instance to prevent duplicates
    // Type assertion is safe here because we control the cache and always return the correct type
    this.instanceCache.set(entityType, config as GridConfiguration<unknown>);
    return config;
  }
}
